solutions.python:
class MemoizedComponent(React.Component):
    def __init__(self):
        pass
    def render(self):
        return React.DOM.div(None,
            React.DOM.span(None, self.props.name + ', ' + str(self.props.age)),
            React.DOM.span(None, str(self.props.age)))
    def shouldComponentUpdate(self, nextProps, nextState):
        return nextProps.person === self.props.person
    def getMemoizedProps(self):
        return self.props
MemoizedComponent = React.memo(MemoizedComponent, self.getMemoizedProps)
